package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	accounts map[string]float64
	mu       sync.RWMutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) CreateAccount(accountID string, initialBalance float64) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[accountID] = initialBalance
}

func (b *Bank) GetBalance(accountID string) (float64, bool) {
	b.mu.RLock()
	defer b.mu.RUnlock()
	balance, exists := b.accounts[accountID]
	return balance, exists
}

func (b *Bank) Deposit(accountID string, amount float64) bool {
	if amount <= 0 {
		return false
	}
	
	b.mu.Lock()
	defer b.mu.Unlock()
	
	if _, exists := b.accounts[accountID]; !exists {
		return false
	}
	
	b.accounts[accountID] += amount
	return true
}

func (b *Bank) Withdraw(accountID string, amount float64) bool {
	if amount <= 0 {
		return false
	}
	
	b.mu.Lock()
	defer b.mu.Unlock()
	
	balance, exists := b.accounts[accountID]
	if !exists {
		return false
	}
	
	if balance < amount {
		return false
	}
	
	b.accounts[accountID] -= amount
	return true
}

func (b *Bank) Transfer(fromID, toID string, amount float64) bool {
	if amount <= 0 {
		return false
	}
	
	b.mu.Lock()
	defer b.mu.Unlock()
	
	fromBalance, fromExists := b.accounts[fromID]
	_, toExists := b.accounts[toID]
	
	if !fromExists || !toExists {
		return false
	}
	
	if fromBalance < amount {
		return false
	}
	
	b.accounts[fromID] -= amount
	b.accounts[toID] += amount
	return true
}

func main() {
	bank := NewBank()
	
	bank.CreateAccount("Alice", 1000.0)
	bank.CreateAccount("Bob", 500.0)
	bank.CreateAccount("Charlie", 750.0)
	
	var wg sync.WaitGroup
	
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 10; i++ {
			bank.Deposit("Alice", 50.0)
		}
	}()
	
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 5; i++ {
			bank.Withdraw("Bob", 20.0)
		}
	}()
	
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 3; i++ {
			bank.Transfer("Charlie", "Alice", 100.0)
		}
	}()
	
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 10; i++ {
			balance, _ := bank.GetBalance("Alice")
			fmt.Printf("Alice balance: %.2f\n", balance)
		}
	}()
	
	wg.Wait()
	
	fmt.Println("\nFinal Balances:")
	for _, account := range []string{"Alice", "Bob", "Charlie"} {
		balance, _ := bank.GetBalance(account)
		fmt.Printf("%s: %.2f\n", account, balance)
	}
}